import{_ as s,o as a,c as n,V as l}from"./chunks/framework.4bd398b5.js";const d=JSON.parse('{"title":"ssh 免密登录","description":"","frontmatter":{},"headers":[],"relativePath":"develop/linux/SSHPassfree.md","filePath":"develop/linux/SSHPassfree.md","lastUpdated":1685591245000}'),o={name:"develop/linux/SSHPassfree.md"},p=l(`<h1 id="ssh-免密登录" tabindex="-1">ssh 免密登录 <a class="header-anchor" href="#ssh-免密登录" aria-label="Permalink to &quot;ssh 免密登录&quot;">​</a></h1><h2 id="_1-配置-sshd-config" tabindex="-1">1.配置 sshd_config <a class="header-anchor" href="#_1-配置-sshd-config" aria-label="Permalink to &quot;1.配置 sshd_config&quot;">​</a></h2><p>服务端开启免密登录配置, 配置文件位置: <code>/etc/ssh/sshd_config</code>, 开启如下配置, 修改完之后之执行 <code>systemctl restart sshd</code> 重启服务</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 是否允许 root 远程登录</span></span>
<span class="line"><span style="color:#FFCB6B;">PermitRootLogin</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">yes</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 密码登录是否打开</span></span>
<span class="line"><span style="color:#FFCB6B;">PasswordAuthentication</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">yes</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 开启公钥认证</span></span>
<span class="line"><span style="color:#FFCB6B;">RSAAuthentication</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">yes</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;"># 这个参数可能没有</span></span>
<span class="line"><span style="color:#FFCB6B;">PubkeyAuthentication</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">yes</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 存放登录用户公钥的文件位置</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 位置就是登录用户名的家目录下的 .ssh</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># root 就是 /root/.ssh</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># jor 就是 /home/jor/.ssh</span></span>
<span class="line"><span style="color:#FFCB6B;">AuthorizedKeysFile</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">.ssh/authorized_keys</span></span></code></pre></div><h2 id="_2-生成密钥" tabindex="-1">2.生成密钥 <a class="header-anchor" href="#_2-生成密钥" aria-label="Permalink to &quot;2.生成密钥&quot;">​</a></h2><p>用户端生成公钥私钥, 并复制到服务器配置文件中, 免密配置成功</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">ssh-keygen</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-t</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">rsa</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-C</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">commit</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FFCB6B;">ssh-copy-id</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-i</span><span style="color:#A6ACCD;"> (-o </span><span style="color:#C3E88D;">HostKeyAlgorithms=+ssh-rsa</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-o</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">PubkeyAcceptedKeyTypes=+ssh-rsa</span><span style="color:#A6ACCD;">) </span><span style="color:#89DDFF;">~</span><span style="color:#A6ACCD;">/.ssh/id_rsa.pub 服务器用户名@服务器地址</span></span></code></pre></div><h2 id="_3-配置别名-可选" tabindex="-1">3.配置别名(可选) <a class="header-anchor" href="#_3-配置别名-可选" aria-label="Permalink to &quot;3.配置别名(可选)&quot;">​</a></h2><p>可配置别名, 方便登录, <strong>如果使用的协议不是 ssh-rsa 则需配置该文件, 指定 IdentityFile, 否则免密登录不生效</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 登录的服务器别名 ssh examp 就可以了</span></span>
<span class="line"><span style="color:#FFCB6B;">Host</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">examp</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">HostName</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">233.233</span><span style="color:#C3E88D;">.233.233</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;"># 要登录的服务器ip</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">Port</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">22</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">User</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">root</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;"># 登录名</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">IdentityFile</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">~/.ssh/id_rsa</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;"># 你的私钥路径</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#676E95;font-style:italic;"># 服务器版本低于 8.8p1 时添加</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">HostKeyAlgorithms</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">+ssh-rsa</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">PubkeyAcceptedKeyTypes</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">+ssh-rsa</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">ps:</p><p>对于版本 &gt;= 8.8p1 的 openssh, ssh 客户端默认禁用了 ssh-rsa 算法, 但是服务器端未升级 openssh 只支持 ssh-rsa, 当无法升级远程服务器的 openssh 版本或修改配置使用更安全的算法时, 可在连接或配置别名的时候指定算法, 保证远程连接成功</p></div>`,11),e=[p];function t(c,r,i,y,C,h){return a(),n("div",null,e)}const D=s(o,[["render",t]]);export{d as __pageData,D as default};
